import { useEffect, useState } from "react";
import axios from "axios";

function Appointments() {
  const user = JSON.parse(localStorage.getItem("user"));
  const [data, setData] = useState([]);

  useEffect(() => {
    axios.get(`http://localhost:5000/api/appointments?userId=${user._id}&role=${user.role}&name=${user.name}`)
      .then(res => setData(res.data));
  }, []);

  const updateStatus = async (id, status) => {
    await axios.post("http://localhost:5000/api/appointments/status", { id, status });
    window.location.reload();
  };

  return (
    <div className="main">
      <h2>Appointments</h2>

      {data.map(a => (
        <div key={a._id} className="card-box">
          <p><b>Doctor:</b> {a.doctorName}</p>
          <p><b>Patient:</b> {a.patientName}</p>
          <p><b>Problem:</b> {a.problem}</p>
          <p><b>Symptoms:</b> {a.symptoms}</p>
          <p><b>Phone:</b> {a.phone}</p>
          <p><b>Status:</b> {a.status}</p>

          {user.role === "doctor" && (
            <>
              <button onClick={() => updateStatus(a._id, "confirmed")}>
                Confirm
              </button>

              <button onClick={() => updateStatus(a._id, "cancelled")}>
                Cancel
              </button>
            </>
          )}
        </div>
      ))}
    </div>
  );
}

export default Appointments;
